patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index d7afe2f426d3..86ee868caee0 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -2591,6 +2591,16 @@ bool VectorCombine::shrinkType(llvm::Instruction &I) {
       !match(&I, m_LShr(m_ZExt(m_Value(ZExted)), m_Value(OtherOperand))))
     return false;

+  // If we are shrinking to a 1-bit type, we can't sink the zext through
+  // a shift operation unless the shift amount is known to be zero. A
+  // non-zero shift of a 1-bit integer is poison.
+  if (I.getOpcode() == Instruction::LShr) {
+    auto *ZExt = cast<ZExtInst>(I.getOperand(I.getOperand(0) == OtherOperand ? 1 : 0));
+    if (ZExt->getSrcTy()->getScalarType()->isIntegerTy(1) &&
+        !isa<ConstantAggregateZero>(OtherOperand))
+      return false;
+  }
+
   Value *ZExtOperand = I.getOperand(I.getOperand(0) == OtherOperand ? 1 : 0);

   auto *BigTy = cast<FixedVectorType>(I.getType());

reason_thou:
The logic to sink a `zext` through a binary operator in `shrinkType` is too aggressive for shift instructions. When the destination type is being shrunk to a single bit, the only valid, non-poison shift amount is 0. The transformation `lshr (zext V), S` to `zext (lshr V, trunc S)` is only valid if all elements of `S` are known to be 0 when `V` is `i1`. The fix is to add a check to ensure that if we are shrinking the shifted value to 1 bit, the shift amount is all zeros.

